#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long K; scanf("%d %lld", &N, &K);
        long long cnt = 0;
        for(int i=0;i<N;i++){
            long long a; scanf("%lld", &a);
            if(a % K == 0) cnt++;
        }
        printf("%lld\n", cnt);
    }
    return 0;
}

