import sys

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        K = int(next(it))
        cnt = 0
        for _ in range(N):
            a = int(next(it))
            if a % K == 0:
                cnt += 1
        out.append(str(cnt))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

